import{_ as a,o as d,c as e,a2 as r}from"./chunks/framework.ZhLefgN8.js";const u=JSON.parse('{"title":"资产概览","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"portfolio-and-statements/overview.md","filePath":"zh-CN/portfolio-and-statements/overview.md"}'),o={name:"portfolio-and-statements/overview.md"};function h(l,t,i,n,s,p){return d(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="资产概览" tabindex="-1">资产概览 <a class="header-anchor" href="#资产概览" aria-label="Permalink to &quot;资产概览&quot;">​</a></h1><p>资产页是长桥 App 的资产管理中心，展示账户总资产、持仓明细和快捷操作入口。</p><h2 id="页面入口" tabindex="-1">页面入口 <a class="header-anchor" href="#页面入口" aria-label="Permalink to &quot;页面入口&quot;">​</a></h2><p>底部导航「资产」。</p><h2 id="顶部总资产卡片" tabindex="-1">顶部总资产卡片 <a class="header-anchor" href="#顶部总资产卡片" aria-label="Permalink to &quot;顶部总资产卡片&quot;">​</a></h2><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td>总资产</td><td>当前账户所有资产折算后的总价值</td></tr><tr><td>当日盈亏</td><td>今日的浮动盈亏金额及百分比</td></tr><tr><td>持仓市值</td><td>当前持有股票、基金等的市值总和</td></tr><tr><td>可用资金</td><td>账户中可用于交易或出金的现金</td></tr><tr><td>累计盈亏</td><td>历史累计盈亏金额</td></tr></tbody></table><p>点击右上角眼睛图标可隐藏/显示资产数字。</p><h2 id="快捷功能栏" tabindex="-1">快捷功能栏 <a class="header-anchor" href="#快捷功能栏" aria-label="Permalink to &quot;快捷功能栏&quot;">​</a></h2><ul><li><strong>存入资金</strong> — 快速发起入金操作</li><li><strong>提取资金</strong> — 快速发起出金操作</li><li><strong>全部功能</strong> — 展开完整功能列表</li></ul><h2 id="持仓视图" tabindex="-1">持仓视图 <a class="header-anchor" href="#持仓视图" aria-label="Permalink to &quot;持仓视图&quot;">​</a></h2><p>持仓区域按市场分标签展示所有持仓：</p><table tabindex="0"><thead><tr><th>标签</th><th>说明</th></tr></thead><tbody><tr><td>全部</td><td>汇总显示所有市场的持仓</td></tr><tr><td>港股</td><td>仅显示港股持仓</td></tr><tr><td>美股</td><td>仅显示美股持仓</td></tr><tr><td>期权</td><td>显示期权持仓</td></tr><tr><td>其他</td><td>其他市场或产品的持仓</td></tr></tbody></table><p>每条持仓记录包含：股票名称 / 代码、持仓数量、成本价、最新价、市值、浮动盈亏金额及百分比。资产页显示全美行情最新价，进入个股详情页后按账户行情等级显示，两者可能存在细微差异。</p><h2 id="账户切换" tabindex="-1">账户切换 <a class="header-anchor" href="#账户切换" aria-label="Permalink to &quot;账户切换&quot;">​</a></h2><p>点击顶部账户名称或切换按钮，可在多个账户之间切换查看资产（综合账户、标准账户等）。</p><h2 id="字段计算说明" tabindex="-1">字段计算说明 <a class="header-anchor" href="#字段计算说明" aria-label="Permalink to &quot;字段计算说明&quot;">​</a></h2><h3 id="总资产" tabindex="-1">总资产 <a class="header-anchor" href="#总资产" aria-label="Permalink to &quot;总资产&quot;">​</a></h3><p>所有币种现金及持仓（股票、权证、期权、基金、OTC）按实时汇率折算为选定币种的市值之和。汇率为参考值，不代表真实兑换；跨币种展示可能因汇率差导致细微误差。</p><h3 id="当日盈亏" tabindex="-1">当日盈亏 <a class="header-anchor" href="#当日盈亏" aria-label="Permalink to &quot;当日盈亏&quot;">​</a></h3><p>从上一交易日收盘价到当前时段的累计盈亏。</p><p><strong>计算公式</strong>：当日盈亏 = 最新价 × 当前持仓数量 − 昨收价 × 昨收持仓数量 + 当日卖出成交额 − 当日买入成交额</p><p>美股当日盈亏受盘前盘后与夜盘开关影响，可在「设置」→「资产设置」中调整。开关说明：</p><table tabindex="0"><thead><tr><th>盘前盘后</th><th>夜盘</th><th>最新价范围</th><th>统计周期（美东时间）</th></tr></thead><tbody><tr><td>开启</td><td>开启</td><td>含盘前盘后价</td><td>T 日 20:00 ～ T+1 日 20:00</td></tr><tr><td>开启</td><td>关闭</td><td>含盘前盘后价（夜盘取盘后价）</td><td>T 日 04:00 ～ T+1 日 04:00</td></tr><tr><td>关闭</td><td>开启</td><td>不含盘前盘后价</td><td>T 日 20:00 ～ T+1 日 20:00</td></tr><tr><td>关闭</td><td>关闭</td><td>仅昨收价和盘中价</td><td>T 日 04:00 ～ T+1 日 04:00</td></tr></tbody></table><h3 id="当日盈亏率" tabindex="-1">当日盈亏率 <a class="header-anchor" href="#当日盈亏率" aria-label="Permalink to &quot;当日盈亏率&quot;">​</a></h3><p>当日盈亏率 = 单只股票当日盈亏额 ÷ 相应股票持仓投入</p><p>持仓投入 = 期初持仓 × 上一交易日收盘价 + ∑当日买入 × 买入成交价</p><p>若（持仓投入 − 当日盈亏额）&lt; 0，盈亏率显示为 0.00%。</p><h3 id="持仓盈亏" tabindex="-1">持仓盈亏 <a class="header-anchor" href="#持仓盈亏" aria-label="Permalink to &quot;持仓盈亏&quot;">​</a></h3><p>从开仓后累计的盈亏，与成本价相关，不含手续费。支持&quot;摊薄成本&quot;和&quot;平均买入成本&quot;两种算法，默认为摊薄成本。</p><ul><li>多头持仓盈亏 =（现价 − 成本）× 当前数量</li><li>空头持仓盈亏 =（成本 − 现价）× 当前数量</li></ul><p>可在「资产首页」→「全部功能」→「资产设置」→「成本计算方式」切换。</p><h3 id="持仓占比" tabindex="-1">持仓占比 <a class="header-anchor" href="#持仓占比" aria-label="Permalink to &quot;持仓占比&quot;">​</a></h3><p>持仓占比 = 持仓市值 ÷ 对应币种折算的总资产金额 × 100%</p><p>因总资产排除融资欠款，持仓占比可能超过 100%。</p>',34)])])}const c=a(o,[["render",h]]);export{u as __pageData,c as default};
